// shadcn
import { Button } from "@/components/ui/button";

// constants
const featuredProduct = {
  name: "Folding Chair",
  price: "$140",
  image: "https://cdn.uiable.com/block/e-commerce8-1.jpg",
};

const rightProducts = [
  {
    name: "Lounge Sofa",
    price: "$1580",
    image: "https://cdn.uiable.com/block/e-commerce8-2.jpg",
  },
  {
    name: "Folding Chair",
    price: "$140",
    image: "https://cdn.uiable.com/block/e-commerce8-3.jpg",
  },
  {
    name: "Folding Chair",
    price: "$140",
    image: "https://cdn.uiable.com/block/e-commerce8-4.jpg",
  },
];

//  ------------------------------ | E - COMMERCE 8 | ------------------------------  //

export default function Ecommerce8() {
  return (
    <section className="bg-primary py-16 sm:py-20">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Heading */}
        <div className="mx-auto max-w-2xl text-center">
          <p className="text-lg font-medium uppercase tracking-widest text-yellow-500">
            E-commerce
          </p>
          <h2 className="mt-3 text-white">Product You Need</h2>
        </div>

        {/* Product Grid */}
        <div className="mt-10 grid grid-cols-12 gap-6">
          {/* Left Featured Product */}
          <article className="col-span-12 md:col-span-6 rounded-3xl p-4 sm:p-6 overflow-hidden">
            <div className="flex h-full flex-col">
              <div className="flex justify-center">
                <img
                  src={featuredProduct.image}
                  alt={featuredProduct.name}
                  className="h-auto w-full max-w-xs sm:max-w-sm object-contain"
                />
              </div>

              <div className="mt-auto grid grid-cols-12 items-end gap-6 pt-6">
                <div className="col-span-7 sm:col-span-8">
                  <p className="text-lg font-semibold">
                    {featuredProduct.name}
                  </p>
                  <p className="mt-1 text-lg">{featuredProduct.price}</p>
                </div>

                <div className="col-span-5 sm:col-span-4 flex justify-end">
                  <Button
                    size="lg"
                    className="rounded-full bg-yellow-500 text-background hover:bg-yellow-400"
                  >
                    Shop Now
                  </Button>
                </div>
              </div>
            </div>
          </article>

          {/* Right Side Products */}
          <div className="col-span-12 md:col-span-6 grid grid-cols-12 gap-6">
            {/* Top Wide Card */}
            <article className="col-span-12 rounded-3xl p-4 sm:p-5 overflow-hidden">
              <div className="flex h-full flex-col">
                <div className="flex justify-center">
                  <img
                    src={rightProducts[0].image}
                    alt={rightProducts[0].name}
                    className="h-auto w-full max-w-md object-contain"
                  />
                </div>

                <div className="pt-4">
                  <p className="text-lg font-semibold">
                    {rightProducts[0].name}
                  </p>
                  <p className="mt-1 text-lg">{rightProducts[0].price}</p>
                </div>
              </div>
            </article>

            {/* Bottom Two Cards */}
            {rightProducts.slice(1).map((product) => (
              <article
                key={product.image}
                className="col-span-12 sm:col-span-6 rounded-3xl p-4 overflow-hidden"
              >
                <div className="flex h-full flex-col">
                  <div className="flex justify-center">
                    <img
                      src={product.image}
                      alt={product.name}
                      className="h-auto w-full max-w-35 object-contain"
                    />
                  </div>

                  <div className="pt-4">
                    <p className="text-lg font-semibold">{product.name}</p>
                    <p className="mt-1 text-lg">{product.price}</p>
                  </div>
                </div>
              </article>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
